import hashlib
from functools import lru_cache

def _cache_key(query: str, doc: str) -> str:
    return hashlib.sha256(f"{query}||{doc}".encode()).hexdigest()[:16]

# Simple in-memory cache — replace with Redis for distributed deployments
_score_cache: dict[str, float] = {}

def cached_rerank(
    reranker: CrossEncoder,
    query: str,
    documents: list[str],
) -> list[float]:
    missing_indices = []
    scores = [None] * len(documents)

    for idx, doc in enumerate(documents):
        key = _cache_key(query, doc)
        if key in _score_cache:
            scores[idx] = _score_cache[key]
        else:
            missing_indices.append(idx)

    if missing_indices:
        pairs = [(query, documents[i]) for i in missing_indices]
        new_scores = reranker.predict(pairs)
        for idx, score in zip(missing_indices, new_scores):
            key = _cache_key(query, documents[idx])
            _score_cache[key] = float(score)
            scores[idx] = float(score)

    return scores
